62	/**
63	 * @brief Writes data to ADF4382 over SPI.
64	 * @param dev	   - The device structure.
65	 * @param reg_addr - The register address.
66	 * @param data 	   - Data value to write.
67	 * @return 	   - 0 in case of success or negative error code otherwise.
68	 */
69	int adf4382_spi_write(struct adf4382_dev *dev, uint16_t reg_addr, uint8_t data)
70	{
71		uint8_t buff[ADF4382_BUFF_SIZE_BYTES];
72		uint16_t cmd;
73	
74		if (!dev)
75			return -EINVAL;
76	
77		cmd = ADF4382_SPI_WRITE_CMD | reg_addr;
78		if (dev->spi_desc->bit_order) {
79			buff[0] = no_os_bit_swap_constant_8(cmd & 0xFF);
80			buff[1] = no_os_bit_swap_constant_8(cmd >> 8);
81			buff[2] = no_os_bit_swap_constant_8(data);
82		} else {
83			buff[0] = cmd >> 8;
84			buff[1] = cmd & 0xFF;
85			buff[2] = data;
86		}
87	
88		return no_os_spi_write_and_read(dev->spi_desc, buff,
89						ADF4382_BUFF_SIZE_BYTES);
90	}
91	
92	/**
93	 * @brief Reads data from ADF4382 over SPI.
94	 * @param dev 	   - The device structure.
95	 * @param reg_addr - The register address.
96	 * @param data	   - Data read from the device.
97	 * @return	   - 0 in case of success or negative error code otherwise.
98	 */
99	int adf4382_spi_read(struct adf4382_dev *dev, uint16_t reg_addr, uint8_t *data)
100	{
101		int ret;
102		uint8_t buff[ADF4382_BUFF_SIZE_BYTES];
103		uint16_t cmd;
104	
105		if (!dev)
106			return -EINVAL;
107	
108		cmd = ADF4382_SPI_READ_CMD | reg_addr;
109		if (dev->spi_desc->bit_order) {
110			buff[0] = no_os_bit_swap_constant_8(cmd & 0xFF);
111			buff[1] = no_os_bit_swap_constant_8(cmd >> 8);
112			buff[2] = no_os_bit_swap_constant_8(ADF4382_SPI_DUMMY_DATA);
113		} else {
114			buff[0] = cmd >> 8;
115			buff[1] = cmd & 0xFF;
116			buff[2] = ADF4382_SPI_DUMMY_DATA;
117		}
118	
119		ret = no_os_spi_write_and_read(dev->spi_desc, buff,
120					       ADF4382_BUFF_SIZE_BYTES);
121		if (ret)
122			return ret;
123	
124		*data = buff[2];
125	
126		return 0;
127	}
128	
129	/**
130	 * @brief Updates the values of the ADF4382 register.
131	 * @param dev 	   - The device structure.
132	 * @param reg_addr - The register address.
133	 * @param mask 	   - Bits to be updated.
134	 * @param data 	   - Update value for the mask.
135	 * @return	   - 0 in case of success or negative error code otherwise.
136	 */
137	int adf4382_spi_update_bits(struct adf4382_dev *dev, uint16_t reg_addr,
138				    uint8_t mask, uint8_t data)
139	{
140		uint8_t tmp, orig;
141		int ret;
142	
143		ret = adf4382_spi_read(dev, reg_addr, &orig);
144		if (ret)
145			return ret;
146	
147		tmp = orig & ~mask;
148		tmp |= data & mask;
149	
150		if (tmp != orig)
151			return adf4382_spi_write(dev, reg_addr, tmp);
152	
153		return 0;
154	}
