156	/**
157	 * @brief Will output on the terminal the values of all the ADF4382 registers.
158	 * @param dev 	- The device structure.
159	 * @return 	- 0 in case of success or negative error code.
160	 */
161	int adf4382_reg_dump(struct adf4382_dev *dev)
162	{
163		uint8_t val;
164		uint16_t i;
165		int ret;
166	
167		for (i = 0; i < 0x68; i++) {
168			ret = adf4382_spi_read(dev, i, &val);
169			if (ret)
170				return ret;
171	
172			pr_info("0x%X    0x%X\n", i, val);
173		}
174	
175		for (i = 0x100; i < 0x112; i++) {
176			ret = adf4382_spi_read(dev, i, &val);
177			if (ret)
178				return ret;
179	
180			pr_info("0x%X    0x%X\n", i, val);
181		}
182	
183		for (i = 0x200; i < 0x274; i++) {
184			ret = adf4382_spi_read(dev, i, &val);
185			if (ret)
186				return ret;
187	
188			pr_info("0x%X    0x%X\n", i, val);
189		}
190	
191		return ret;
192	}
