194	/**
195	 * @brief Set the desired reference frequency and reset everything over to maximum
196	 * supported value of 5GHz to the max. value and everything under the minimum
197	 * supported value of 10MHz to the min. value. This should also update the
198	 * frequency and the VCO calibration values.
199	 * @param dev 		- The device structure.
200	 * @param val		- The desired reference frequency in Hz.
201	 * @return    		- 0 in case of success or negative error code.
202	 */
203	int adf4382_set_ref_clk(struct adf4382_dev *dev, uint64_t val)
204	{
205		int ret;
206	
207		if (!dev)
208			return -EINVAL;
209	
210		dev->ref_freq_hz = val;
211	
212		if (val > ADF4382_REF_CLK_MAX)
213			dev->ref_freq_hz = ADF4382_REF_CLK_MAX;
214	
215		if (val < ADF4382_REF_CLK_MIN)
216			dev->ref_freq_hz = ADF4382_REF_CLK_MIN;
217	
218		ret = adf4382_set_freq(dev);
219		if (ret)
220			return ret;
221		return adf4382_set_vco_cal_timeout(dev);
222	}
223	
224	/**
225	 * @brief Gets the user proposed reference frequency
226	 * @param dev 		- The device structure.
227	 * @param val		- The set value of the reference frequency in Hz.
228	 * @return    		- Reference frequency in KHz.
229	 */
230	int adf4382_get_ref_clk(struct adf4382_dev *dev, uint64_t *val)
231	{
232		if (!dev)
233			return -EINVAL;
234	
235		*val = dev->ref_freq_hz;
236	
237		return 0;
238	}
