240	/**
241	 * @brief Set the reference doubler to enable or disable based on the passed
242	 * parameter. If the parameter is different then 0 it will set the doubler to
243	 * enable. This should also update the frequency and the VCO calibration values.
244	 * @param dev 		- The device structure.
245	 * @param en	 	- The enable or disable value of the reference doubler.
246	 * @return    		- 0 in case of success or negative error code.
247	 */
248	int adf4382_set_en_ref_doubler(struct adf4382_dev *dev, bool en)
249	{
250		int ret;
251	
252		if (!dev)
253			return -EINVAL;
254	
255		dev->ref_doubler_en = en;
256	
257		ret = adf4382_set_freq(dev);
258		if (ret)
259			return ret;
260		return adf4382_set_vco_cal_timeout(dev);
261	}
