263	/**
264	 * @brief Gets the value the doubler if it is enabled or disable and stores it
265	 * it the dev structure.
266	 * @param dev 		- The device structure.
267	 * @param en		- The read value of the reference doubler.
268	 * @return    		- 0 in case of success or negative error code.
269	 */
270	int adf4382_get_en_ref_doubler(struct adf4382_dev *dev, bool *en)
271	{
272		uint8_t tmp;
273		int ret;
274	
275		ret = adf4382_spi_read(dev, 0x20, &tmp);
276		if (ret)
277			return ret;
278	
279		dev->ref_doubler_en = no_os_field_get(tmp, ADF4382_EN_RDBLR_MSK);
280		*en = dev->ref_doubler_en;
281	
282		return 0;
283	}
