285	/**
286	 * @brief Set the reference divider value and reset everything over to maximum
287	 * supported value of 63 to the max. value
288	 * @param dev 		- The device structure.
289	 * @param div	 	- The reference divider value.
290	 * @return    		- 0 in case of success or negative error code.
291	 */
292	int adf4382_set_ref_div(struct adf4382_dev *dev, int32_t div)
293	{
294		int ret;
295	
296		if (!dev)
297			return -EINVAL;
298	
299		dev->ref_div = div;
300	
301		if (div > ADF4382_REF_DIV_MAX)
302			dev->ref_div = ADF4382_REF_DIV_MAX;
303	
304		ret = adf4382_set_freq(dev);
305		if (ret)
306			return ret;
307		return adf4382_set_vco_cal_timeout(dev);
