331	/**
332	 * @brief Set the charge pump value which will be written to the register. The
333	 * value will be between 0 and 15 on 8 bits. For more information please
334	 * consult the Datasheet.
335	 * @param dev 		- The device structure.
336	 * @param reg_val 	- The desired charge pump register value.
337	 * @return    		- 0 in case of success or negative error code.
338	 */
339	int adf4382_set_cp_i(struct adf4382_dev *dev, int32_t reg_val)
340	{
341		if (!dev)
342			return -EINVAL;
343	
344		dev->cp_i = (uint8_t)reg_val;
345	
346		if (reg_val > ADF4382_CPI_VAL_MAX)
347			dev->cp_i = ADF4382_CPI_VAL_MAX;
348	
349		return adf4382_set_freq(dev);
350	}
351	
352	/**
353	 * @brief Gets the charge pump value from the register. The value will be
354	 * between 0 and 15 on 8 bits. For more information please consult the
355	 * Datasheet.
356	 * @param dev 		- The device structure.
357	 * @param reg_val 	- The read charge pump register value.
358	 * @return    		- 0 in case of success or negative error code.
359	 */
360	int adf4382_get_cp_i(struct adf4382_dev *dev, int32_t *reg_val)
361	{
362		uint8_t tmp;
363		int ret;
364	
365		ret = adf4382_spi_read(dev, 0x1F, &tmp);
366		if (ret)
367			return ret;
368	
369		dev->cp_i = no_os_field_get(ADF4382_CP_I_MSK, tmp);
370		*reg_val = dev->cp_i;
371	
372		return 0;
373	}
374	
375	/**
376	 * @brief Set the bleed word, which represents the value of the bleed current
377	 * written to the register space.
378	 * @param dev 		- The device structure.
379	 * @param word	 	- The bleed current register value.
380	 * @return    		- 0 in case of success or negative error code.
381	 */
382	int adf4382_set_bleed_word(struct adf4382_dev *dev, int32_t word)
383	{
384		if (!dev)
385			return -EINVAL;
386	
387		dev->bleed_word = (uint16_t)word;
388	
389		if (word > ADF4382_BLEED_WORD_MAX)
390			dev->bleed_word = ADF4382_BLEED_WORD_MAX;
391	
392		return adf4382_set_freq(dev);
393	}
394	
395	/**
396	 * @brief Gets the value of the set bleed word.
397	 * @param dev 		- The device structure.
398	 * @param word	 	- The read bleed current register value.
399	 * @return    		- Result of the reading procedure, error code otherwise.
400	 */
401	int adf4382_get_bleed_word(struct adf4382_dev *dev, int32_t *word)
402	{
403		uint8_t upper;
404		uint8_t lower;
405		int ret;
406	
407		ret = adf4382_spi_read(dev, 0x1E, &upper);
408		if (ret)
409			return ret;
410	
411		upper &= (ADF4382_COARSE_BLEED_MSK | ADF4382_FINE_BLEED_MSB_MSK);
412	
413		ret = adf4382_spi_read(dev, 0x1D, &lower);
414		if (ret)
415			return ret;
416	
417		dev->bleed_word = (upper << 8) | lower;
418		*word = dev->bleed_word;
419	
420		return 0;
421	}
