534	int adf4382_set_rfout(struct adf4382_dev *dev, uint64_t val)
535	{
536		if (!dev)
537			return -EINVAL;
538	
539		dev->freq = val;
540	
541		if (val > dev->freq_max)
542			dev->freq = dev->freq_max;
