550	/**
551	 * @brief Computes the PFD frequency and returns the value in Hz.
552	 * @param dev 	     - The device structure.
553	 * @return 	     - PFD value in Hz.
554	 */
555	static uint64_t adf4382_pfd_compute(struct adf4382_dev *dev)
556	{
557		uint64_t pfd_freq;
558	
559		pfd_freq = NO_OS_DIV_ROUND_CLOSEST(dev->ref_freq_hz, dev->ref_div);
560		if (dev->ref_doubler_en)
561			pfd_freq *=  2;
562	
563		return pfd_freq;
564	}
