566	/**
567	 * @brief Gets the user proposed output frequency
568	 * @param dev 		- The device structure.
569	 * @param val		- The set value of the output frequency in Hz.
570	 * @return    		- 0 in case of success or negative error code.
571	 */
572	int adf4382_get_rfout(struct adf4382_dev *dev, uint64_t *val)
573	{
574		uint32_t frac1 = 0;
575		uint32_t frac2 = 0;
576		uint32_t mod2 = 0;
577		uint64_t freq;
578		uint64_t pfd;
579		uint8_t tmp;
580		uint16_t n;
581		int ret;
582	
583		pfd = adf4382_pfd_compute(dev);
584	
585		ret = adf4382_spi_read(dev, 0x11, &tmp);
586		if (ret)
587			return ret;
588		n = tmp & ADF4382_N_INT_MSB_MSK;
589		n = n << 8;
590	
591		ret = adf4382_spi_read(dev, 0x10, &tmp);
592		if (ret)
593			return ret;
594		n |= tmp;
595	
596		ret = adf4382_spi_read(dev, 0x15, &tmp);
597		if (ret)
598			return ret;
599		frac1 = tmp & ADF4382_FRAC1WORD_MSB;
600		frac1 = frac1 << 8;
601	
602		ret = adf4382_spi_read(dev, 0x14, &tmp);
603		if (ret)
604			return ret;
605		frac1 |= tmp;
606		frac1 = frac1 << 8;
607	
608		ret = adf4382_spi_read(dev, 0x13, &tmp);
609		if (ret)
610			return ret;
611		frac1 |= tmp;
612		frac1 = frac1 << 8;
613	
614		ret = adf4382_spi_read(dev, 0x12, &tmp);
615		if (ret)
616			return ret;
617		frac1 |= tmp;
618	
619		ret = adf4382_spi_read(dev, 0x19, &tmp);
620		if (ret)
621			return ret;
622		frac2 = tmp;
623		frac2 = frac2 << 8;
624	
625		ret = adf4382_spi_read(dev, 0x18, &tmp);
626		if (ret)
627			return ret;
628		frac2 |= tmp;
629		frac2 = frac2 << 8;
630	
631		ret = adf4382_spi_read(dev, 0x17, &tmp);
632		if (ret)
633			return ret;
634		frac2 |= tmp;
635	
636		ret = adf4382_spi_read(dev, 0x1c, &tmp);
637		if (ret)
638			return ret;
639		mod2 = tmp;
640		mod2 = mod2 << 8;
641	
642		ret = adf4382_spi_read(dev, 0x1b, &tmp);
643		if (ret)
644			return ret;
645		mod2 |= tmp;
646		mod2 = mod2 << 8;
647	
648		ret = adf4382_spi_read(dev, 0x1a, &tmp);
649		if (ret)
650			return ret;
651		mod2 |= tmp;
652	
653		freq = frac2 * pfd;
654		freq = no_os_div_u64(freq, mod2);
655		freq = freq + (frac1 * pfd);
656		freq = no_os_div_u64(freq, ADF4382_MOD1WORD);
657		freq = freq + (n * pfd);
658	
659		*val = freq;
660		return 0;
661	}
