663	/**
664	 * @brief Computes the second fractional part of the feedback divider if needed.
665	 * @param dev 	     - The device structure.
666	 * @param res 	     - Residue from the first fractional part.
667	 * @param pfd_freq   - Phase/frequency detector frequency.
668	 * @param frac2_word - Second fractional part of the feedback divider, which
669	 * 		       will be returned.
670	 * @param mod2_word  - Modulo for the second fractional part of the feedback
671	 * 		       divider, which will be returned.
672	 * @return 	     - 0 in case of success, negative error code otherwise.
673	 */
674	static int adf4382_frac2_compute(struct adf4382_dev *dev, uint64_t res,
675					 uint64_t pfd_freq, uint32_t *frac2_word,
676					 uint32_t *mod2_word)
677	{
678		uint32_t channel_spacing;
679		uint8_t en_phase_resync;
680		uint32_t chsp_freq;
681		uint32_t mod2_tmp;
682		uint32_t mod2_max;
683		uint32_t mod2_wd;
684		uint32_t gcd;
685		uint8_t tmp;
686		int ret;
687	
688		channel_spacing = 1;
689		mod2_wd = 1;
690	
691		ret = adf4382_spi_read(dev, 0x1E, &tmp);
692		if (ret)
693			return ret;
694	
695		en_phase_resync = no_os_field_get(tmp, ADF4382_EN_PHASE_RESYNC_MSK);
696	
697		if (en_phase_resync)
698			mod2_max = ADF4382_PHASE_RESYNC_MOD2WORD_MAX;
699		else
700			mod2_max = ADF4382_MOD2WORD_MAX;
701	
702		do {
703	
704			chsp_freq = channel_spacing * ADF4382_MOD1WORD;
705			gcd = no_os_greatest_common_divisor(chsp_freq, pfd_freq);
706			mod2_tmp = NO_OS_DIV_ROUND_UP(pfd_freq, gcd);
707	
708			if (mod2_tmp > mod2_max) {
709				channel_spacing *= 5;
710			} else {
711				mod2_wd = mod2_tmp;
712				break;
713			}
714	
715		} while (channel_spacing < ADF4382_CHANNEL_SPACING_MAX);
716	
717		if (!en_phase_resync) {
718			mod2_wd *= NO_OS_DIV_U64(mod2_max, mod2_wd);
719		}
720	
721		*frac2_word = NO_OS_DIV_ROUND_CLOSEST_ULL(res * mod2_wd, pfd_freq);
722		*mod2_word = mod2_wd;
723	
724		return 0;
725	}
726	
727	/**
728	 * @brief Computes the feedback divider values for the PLL.
729	 * @param dev 	     - The device structure.
730	 * @param freq 	     - The output frequency.
731	 * @param pfd_freq   - Phase/frequency detector frequency.
732	 * @param n_int      - Integer part of the feedback divider, which will be
733	 * 		       returned.
734	 * @param frac1_word - First fractional part of the feedback divider, which will
735	 * 		       be returned.
736	 * @param frac2_word - Second fractional part of the feedback divider, which
737	 * 		       will be returned.
738	 * @param mod2_word  - Modulo for the second fractional part of the feedback
739	 * 		       divider, which will be returned.
740	 * @return 	     - 0 in case of success, negative error code otherwise.
741	 */
742	static int adf4382_pll_fract_n_compute(struct adf4382_dev *dev, uint64_t freq,
743					       uint64_t pfd_freq, uint16_t *n_int,
744					       uint32_t *frac1_word, uint32_t *frac2_word,
745					       uint32_t *mod2_word)
746	{
747		uint64_t rem;
748		uint64_t res;
749	
750		*n_int = no_os_div64_u64_rem(freq, pfd_freq, &rem);
751	
752		res = rem * ADF4382_MOD1WORD;
753		*frac1_word = (uint32_t)no_os_div64_u64_rem(res, pfd_freq, &rem);
754	
755		*frac2_word = 0;
756		*mod2_word = 0;
757	
758		if (rem > 0)
759			return adf4382_frac2_compute(dev, rem, pfd_freq, frac2_word,
760						     mod2_word);
761	
762		return 0;
763	}
