765	/**
766	 * @brief Fast calibration function. Computes Minimum VCO frequency (fmin),
767	 * uses the minimum NDIV value to generate fastcal Lookup table (LUT), and
768	 * finally enables LUT Calibration.
769	 * @param dev 	     - The device structure.
770	 * @param en_fast_cal	- Enables the fast calibration routine.
771	 * @return		- N_INT value corresponding to minimum VCO frequency for
772	 * 		      fast calibration LUT generation.
773	 */
774	int adf4382_set_en_fast_calibration(struct adf4382_dev *dev, bool en_fast_cal)
775	{
776		uint64_t operating_pfd_freq;
777		uint64_t pfd_freq_lut = 0;
778		uint8_t ref_div_lut = 0;
779		uint8_t timeout = 0;
780		uint8_t lut_scale;
781		uint16_t lut_int;
782		uint8_t fsm_busy;
783		uint16_t n_int;
784		uint8_t tmp;
785		uint8_t val;
786		int ret;
787	
788		if (!dev)
789			return -EINVAL;
790	
791		if (!en_fast_cal)
792			return 0;
793	
794		// Stabilize PFD Frequency for Fast Calibration LUT Generation
795		operating_pfd_freq = adf4382_pfd_compute(dev);
796	
797		if (operating_pfd_freq > 125 * MHZ) {
798			ref_div_lut = dev->ref_div;
799			pfd_freq_lut = operating_pfd_freq;
800			// Increase reference divider until PFD frequency is below 125MHz
801			do {
802				dev->ref_div += 1;
803				if (dev->ref_div > ADF4382_REF_DIV_MAX)
804					break;
805				pfd_freq_lut = adf4382_pfd_compute(dev);
806			} while (pfd_freq_lut > 125 * MHZ);
807			ret = adf4382_set_ref_div(dev, dev->ref_div);
808			if (ret)
809				return ret;
810		} else {
811			pfd_freq_lut = operating_pfd_freq;
812		}
813	
814		// Set cal_gen values for fast calibration
815		ret = adf4382_spi_update_bits(dev, 0x44, ADF4382_VPTAT_CALGEN_MSK,
816					      no_os_field_prep
817					      (ADF4382_VPTAT_CALGEN_MSK,
818					       ADF4382_FASTCAL_VPTAT_CALGEN));
819		if (ret)
820			return ret;
821	
822		ret = adf4382_spi_update_bits(dev, 0x45, ADF4382_VCTAT_CALGEN_MSK,
823					      no_os_field_prep
824					      (ADF4382_VCTAT_CALGEN_MSK,
825					       ADF4382_FASTCAL_VCTAT_CALGEN));
826		if (ret)
827			return ret;
828	
829		// Enable LUT Generation
830		dev->en_lut_gen = en_fast_cal;
831		ret = adf4382_spi_update_bits(dev, 0x36, ADF4382_EN_LUT_GEN_MSK,
832					      no_os_field_prep(ADF4382_EN_LUT_GEN_MSK,
833							      dev->en_lut_gen));
834		if (ret)
835			return ret;
836	
837		// Compute and set the minimum N_INT values
838		n_int = NO_OS_DIV_ROUND_UP(dev->vco_min, pfd_freq_lut);
839		val = n_int & ADF4382_N_INT_LSB_MSK;
840		ret = adf4382_spi_write(dev, 0x10, val);
841		if (ret)
842			return ret;
843	
844		// Monitor FSM busy status
845		ret = adf4382_spi_read(dev, 0x58, &val);
846		if (ret)
847			return ret;
848		fsm_busy = no_os_field_get(val, ADF4382_FSM_BUSY_MSK);
849	
850		while (fsm_busy == 1) {
851			if (timeout++ > ADF4382_FSM_BUSY_LOOP_CNT)
852				break;
853			no_os_mdelay(10);
854			ret = adf4382_spi_read(dev, 0x58, &val);
855			if (ret)
856				return ret;
857			fsm_busy = no_os_field_get(val, ADF4382_FSM_BUSY_MSK);
858		}
859		if (timeout > ADF4382_FSM_BUSY_LOOP_CNT)
860			return -ETIMEDOUT;
861	
862		// Compute the LUT scale based on PFD frequency
863		lut_scale = NO_OS_DIV_ROUND_CLOSEST(operating_pfd_freq, pfd_freq_lut);
864		lut_scale *= 8;
865		val = lut_scale & ADF4382_LUT_SCALE_MSK;
866		ret = adf4382_spi_write(dev, 0x4F, val);
867		if (ret)
868			return ret;
869	
870		dev->en_lut_gen = !en_fast_cal;
871		ret = adf4382_spi_update_bits(dev, 0x36, ADF4382_EN_LUT_GEN_MSK,
872					      no_os_field_prep
873					      (ADF4382_EN_LUT_GEN_MSK,
874					       dev->en_lut_gen));
875		if (ret)
876			return ret;
877	
878		// Lock to the maximum frequency
879		dev->freq = dev->freq_max;
880		ret = adf4382_set_freq(dev);
881		if (ret)
882			return ret;
883	
884	
885		// Read LUT int value directly from registers and write it to the LUT
886		ret = adf4382_spi_read(dev, 0x11, &tmp);
887		if (ret)
888			return ret;
889		lut_int = no_os_field_get(tmp, ADF4382_N_INT_MSB_MSK);
890		lut_int = lut_int << 8;
891	
892		ret = adf4382_spi_read(dev, 0x10, &tmp);
893		if (ret)
894			return ret;
895		lut_int |= tmp;
896	
897		val = (lut_int >> 6) & ADF4382_M_LUT_N_MSB_MSK;
898		ret = adf4382_spi_write(dev, 0x203, val);
899		if (ret)
900			return ret;
901	
902		val = lut_int & ADF4382_M_LUT_N_LSB_MSK;
903		ret = adf4382_spi_update_bits(dev, 0x202, ADF4382_M_LUT_N_LSB_MSK,
904					      no_os_field_prep
905					      (ADF4382_M_LUT_N_LSB_MSK, val));
906		if (ret)
907			return ret;
908	
909		ret = adf4382_spi_read(dev, 0x5F, &tmp);
910		if (ret)
911			return ret;
912	
913		val = no_os_field_get(tmp, ADF4382_VCO_CORE_MSK);
914		ret = adf4382_spi_update_bits(dev, 0x202, ADF4382_M_LUT_CORE_MSK,
915					      no_os_field_prep
916					      (ADF4382_M_LUT_CORE_MSK, val));
917		if (ret)
918			return ret;
919	
920		ret = adf4382_spi_read(dev, 0x5E, &tmp);
921		if (ret)
922			return ret;
923	
924		val = no_os_field_get(tmp, ADF4382_VCO_BAND_LSB_MSK);
925		ret = adf4382_spi_write(dev, 0x201, val);
926		if (ret)
927			return ret;
928	
929		ret = adf4382_spi_read(dev, 0x5F, &tmp);
930		if (ret)
931			return ret;
932	
933		val = no_os_field_get(tmp, ADF4382_M_LUT_BAND_MSB_MSK);
934		ret = adf4382_spi_update_bits(dev, 0x202, ADF4382_M_LUT_BAND_MSB_MSK,
935					      no_os_field_prep
936					      (ADF4382_M_LUT_BAND_MSB_MSK, val));
937		if (ret)
938			return ret;
939	
940		val = no_os_field_prep(ADF4382_LUT_WR_ADDR_MSK, 31) |
941		      no_os_field_prep(ADF4382_O_VCO_LUT_MSK, 1);
942		ret = adf4382_spi_write(dev, 0x200, val);
943		if (ret)
944			return ret;
945	
946		// Revert the R_DIV value to original value if changed.
947		if (ref_div_lut != 0) {
948			dev->ref_div = ref_div_lut;
949			ret = adf4382_set_ref_div(dev, dev->ref_div);
950			if (ret)
951				return ret;
952		}
953		dev->en_lut_cal = en_fast_cal;
954		adf4382_spi_update_bits(dev, 0x36, ADF4382_EN_LUT_CAL_MSK,
955					dev->en_lut_cal);
956		if (ret)
957			return ret;
958	
959		ret = adf4382_spi_update_bits(dev, 0x15, ADF4382_INT_MODE_MSK,
960					      no_os_field_prep(ADF4382_INT_MODE_MSK, 0));
961		if (ret)
962			return ret;
963	
964		ret = adf4382_spi_update_bits(dev, 0x2A, ADF4382_PD_CALGEN_MSK,
965					      no_os_field_prep(ADF4382_PD_CALGEN_MSK, 1));
966		if (ret)
967			return ret;
968	
969		return adf4382_spi_update_bits(dev, 0x38, ADF4382_CAL_VTUNE_TO_LSB_MSK,
970					       no_os_field_prep(
971						       ADF4382_CAL_VTUNE_TO_LSB_MSK, 0));
972	}
