1099	/**
1100	 * @brief Computes the optimized bleed word value for the PLL in fractional mode.
1101	 * @param dev 	     - The device structure.
1102	 * @param pfd_freq   - Phase detector frequency.
1103	 * @return 	     - 0 in case of success or negative error code.
1104	 */
1105	static int adf4382_bleed_word_compute(struct adf4382_dev *dev,
1106					      uint64_t pfd_freq)
1107	{
1108		uint32_t coars_bleed;
1109		uint16_t bleed_delay = 0;
1110		uint32_t fine_bleed;
1111		uint16_t bleed_word_tmp;
1112		uint64_t bleed_i;
1113		uint64_t rem;
1114	
1115		if (!dev)
1116			return -EINVAL;
1117	
1118		/* Computes the bleed delay based on rfout frequency in SDM MODE 0.
1119		See Product DataSheet for more details. */
1120		if (dev->freq < 1800000000UL)
1121			bleed_delay = 3600;
1122		else if (dev->freq < 4000000000)
1123			bleed_delay = 1000;
1124		else if (dev->freq < 10000000000UL)
1125			bleed_delay = 625;
1126		else if (dev->freq >= 10000000000UL)
1127			bleed_delay = 300;
1128	
1129		bleed_i = bleed_delay * pfd_freq * adf4382_ci_ua[dev->cp_i];
1130		bleed_i = NO_OS_DIV_ROUND_CLOSEST(bleed_i, PS_TO_S);
1131		coars_bleed = no_os_div64_u64_rem(bleed_i, ADF4382_COARSE_BLEED_CONST,
1132						  &rem);
1133		fine_bleed = rem * ADF4382_FINE_BLEED_CONST_1;
1134		fine_bleed = NO_OS_DIV_ROUND_UP(fine_bleed, ADF4382_FINE_BLEED_CONST_2);
1135		bleed_word_tmp = coars_bleed << 9 | fine_bleed;
1136		bleed_word_tmp = no_os_clamp(bleed_word_tmp, 1, 8191);
1137		dev->bleed_word = bleed_word_tmp;
1138		return 0;
1139	}
