1141	/**
1142	 * @brief Set the output frequency. This will set the required registers to
1143	 * device but skip NDIV value, to be written separately. This Function will not
1144	 * start autocalibration until REG0010 is written.
1145	 * @param dev 	- The device structure.
1146	 * @return    	- 0 in case of success, negative error code otherwise.
1147	 */
1148	int adf4382_set_change_freq(struct adf4382_dev *dev)
1149	{
1150		uint32_t frac2_word;
1151		uint32_t frac1_word;
1152		uint32_t mod2_word;
1153		uint8_t clkout_div;
1154		uint64_t pfd_freq;
1155		uint8_t ldwin_pw = 0;
1156		uint8_t en_bleed;
1157		uint16_t n_int;
1158		uint64_t tmp;
1159		uint64_t vco = 0;
1160		uint8_t val;
1161		int ret;
1162	
1163		for (clkout_div = 0; clkout_div <= dev->clkout_div_reg_val_max; clkout_div++) {
1164			tmp = (1 << clkout_div) * dev->freq;
1165			if (tmp < dev->vco_min || tmp > dev->vco_max)
1166				continue;
1167	
1168			vco = tmp;
1169			break;
1170		}
1171	
1172		if (!vco) {
1173			pr_err("VCO is 0\n");
1174			return -EINVAL;
1175		}
1176	
1177		//Calculates the PFD freq. the output will be in Hz
1178		pfd_freq = adf4382_pfd_compute(dev);
1179	
1180		ret = adf4382_pll_fract_n_compute(dev, dev->freq, pfd_freq, &n_int,
1181						  &frac1_word, &frac2_word, &mod2_word);
1182		if (ret)
1183			return ret;
1184	
1185		if (frac1_word || frac2_word) {
1186			en_bleed = 1;
1187			if (pfd_freq <= 40 * MHZ) {
1188				ldwin_pw = 7;
1189			} else if (pfd_freq <= 50 * MHZ) {
1190				ldwin_pw = 6;
1191			} else if (pfd_freq <= 100 * MHZ) {
1192				ldwin_pw = 5;
1193			} else if (pfd_freq <= 200 * MHZ) {
1194				ldwin_pw = 4;
1195			} else if (pfd_freq <= 250 * MHZ) {
1196				if (dev->freq >= 5000U * MHZ &&
1197				    dev->freq < 6400U * MHZ) {
1198					ldwin_pw = 3;
1199				} else {
1200					ldwin_pw = 2;
1201				}
1202			}
1203			ret = adf4382_bleed_word_compute(dev, pfd_freq);
1204			if (ret)
1205				return ret;
1206		} else {
1207			en_bleed = 0;
1208	
1209			tmp = NO_OS_DIV_ROUND_UP(pfd_freq, MICROAMPER_PER_AMPER);
1210			tmp *= adf4382_ci_ua[dev->cp_i];
1211			tmp = NO_OS_DIV_ROUND_UP(dev->bleed_word, tmp);
1212			if (tmp <= 85)
1213				ldwin_pw = 0;
1214			else
1215				ldwin_pw = 1;
1216		}
1217	
1218		if (frac2_word) {
1219			ret = adf4382_spi_update_bits(dev, 0x28, ADF4382_VAR_MOD_EN_MSK,
1220						      0xff);
1221			if (ret)
1222				return ret;
1223		} else {
1224			ret = adf4382_spi_update_bits(dev, 0x28, ADF4382_VAR_MOD_EN_MSK,
1225						      0x0);
1226			if (ret)
1227				return ret;
1228		}
1229	
1230		val = dev->bleed_word & ADF4382_FINE_BLEED_LSB_MSK;
1231		ret = adf4382_spi_write(dev, 0x1D, val);
1232		if (ret)
1233			return ret;
1234		val = (dev->bleed_word >> 8) & ADF4382_BLEED_MSB_MSK;
1235		ret = adf4382_spi_update_bits(dev, 0x1E, ADF4382_BLEED_MSB_MSK,
1236					      no_os_field_prep(ADF4382_BLEED_MSB_MSK,
1237							      val));
1238		if (ret)
1239			return ret;
1240	
1241		ret = adf4382_spi_update_bits(dev, 0x1F, ADF4382_EN_BLEED_MSK,
1242					      no_os_field_prep(ADF4382_EN_BLEED_MSK,
1243							      en_bleed));
1244		if (ret)
1245			return ret;
1246	
1247		val = mod2_word & ADF4382_MOD2WORD_LSB_MSK;
1248		ret = adf4382_spi_write(dev, 0x1A, val);
1249		if (ret)
1250			return ret;
1251		val = (mod2_word >> 8) & ADF4382_MOD2WORD_MID_MSK;
1252		ret = adf4382_spi_write(dev, 0x1B, val);
1253		if (ret)
1254			return ret;
1255		val = (mod2_word >> 16) & ADF4382_MOD2WORD_MSB_MSK;
1256		ret = adf4382_spi_write(dev, 0x1C, val);
1257		if (ret)
1258			return ret;
1259	
1260		val = frac2_word  & ADF4382_FRAC2WORD_LSB_MSK;
1261		ret = adf4382_spi_write(dev, 0x17, val);
1262		if (ret)
1263			return ret;
1264		val = (frac2_word >> 8)  & ADF4382_FRAC2WORD_MID_MSK;
1265		ret = adf4382_spi_write(dev, 0x18, val);
1266		if (ret)
1267			return ret;
1268		val = (frac2_word >> 16) & ADF4382_FRAC2WORD_MSB_MSK;
1269		ret = adf4382_spi_write(dev, 0x19, val);
1270		if (ret)
1271			return ret;
1272	
1273		val = frac1_word  & ADF4382_FRAC1WORD_LSB_MSK;
1274		ret = adf4382_spi_write(dev, 0x12, val);
1275		if (ret)
1276			return ret;
1277		val = (frac1_word >> 8)  & ADF4382_FRAC1WORD_MID_MSK;
1278		ret = adf4382_spi_write(dev, 0x13, val);
1279		if (ret)
1280			return ret;
1281		val = (frac1_word >> 16) & ADF4382_FRAC1WORD_MSB_MSK;
1282		ret = adf4382_spi_write(dev, 0x14, val);
1283		if (ret)
1284			return ret;
1285	
1286		val = (frac1_word >> 24) & ADF4382_FRAC1WORD_MSB;
1287		ret = adf4382_spi_update_bits(dev, 0x15, ADF4382_FRAC1WORD_MSB, val);
1288		if (ret)
1289			return ret;
1290	
1291		ret = adf4382_spi_update_bits(dev, 0x2C, ADF4382_LDWIN_PW_MSK,
1292					      no_os_field_prep(ADF4382_LDWIN_PW_MSK,
1293							      ldwin_pw));
1294		if (ret)
1295			return ret;
1296	
1297		ret = adf4382_spi_update_bits(dev, 0x11, ADF4382_CLKOUT_DIV_MSK,
1298					      no_os_field_prep(ADF4382_CLKOUT_DIV_MSK,
1299							      clkout_div));
1300		if (ret)
1301			return ret;
1302	
1303		val = (n_int >> 8) & ADF4382_N_INT_MSB_MSK;
1304		ret = adf4382_spi_update_bits(dev, 0x11, ADF4382_N_INT_MSB_MSK, val);
1305		if (ret)
1306			return ret;
1307		// Need to store N_INT to trigger an auto-calibration in another function
1308		dev->n_int = n_int;
1309	
1310		return 0;
1311	}
