1339	 * @brief Set the output frequency.
1340	 * @param dev 	- The device structure.
1341	 * @return    	- 0 in case of success, negative error code otherwise.
1342	 */
1343	int adf4382_set_freq(struct adf4382_dev *dev)
1344	{
1345		uint32_t frac2_word;
1346		uint32_t frac1_word;
1347		uint32_t mod2_word;
1348		uint8_t clkout_div;
1349		uint8_t dclk_div1;
1350		uint64_t pfd_freq;
1351		uint8_t ldwin_pw = 0;
1352		uint8_t int_mode;
1353		uint8_t en_bleed;
1354		uint8_t locked;
1355		uint16_t n_int;
1356		uint8_t div1;
1357		uint64_t tmp;
1358		uint64_t vco = 0;
1359		uint8_t val;
1360		int ret;
1361	
1362		val = no_os_field_prep(ADF4382_EN_RDBLR_MSK, dev->ref_doubler_en) |
1363		      no_os_field_prep(ADF4382_R_DIV_MSK, dev->ref_div);
1364		ret = adf4382_spi_update_bits(dev, 0x20,
1365					      ADF4382_EN_RDBLR_MSK | ADF4382_R_DIV_MSK,
1366					      val);
1367		if (ret)
1368			return ret;
1369	
1370		for (clkout_div = 0; clkout_div <= dev->clkout_div_reg_val_max; clkout_div++) {
1371			tmp = (1 << clkout_div) * dev->freq;
1372			if (tmp < dev->vco_min || tmp > dev->vco_max)
1373				continue;
1374	
1375			vco = tmp;
1376			break;
1377		}
1378	
1379		if (!vco) {
1380			pr_err("VCO is 0\n");
1381			return -EINVAL;
1382		}
1383	
1384		//Calculates the PFD freq. the output will be in Hz
1385		pfd_freq = adf4382_pfd_compute(dev);
1386	
1387		ret = adf4382_spi_update_bits(dev, 0x1F, ADF4382_CP_I_MSK,
1388					      no_os_field_prep(ADF4382_CP_I_MSK,
1389							      dev->cp_i));
