1402			/*The lock detector pulse window is determined based on the
1403			PFD frequency as described in the datasheet*/
1404			if (pfd_freq <= 40 * MHZ) {
1405				ldwin_pw = 7;
1406			} else if (pfd_freq <= 50 * MHZ) {
1407				ldwin_pw = 6;
1408			} else if (pfd_freq <= 100 * MHZ) {
1409				ldwin_pw = 5;
1410			} else if (pfd_freq <= 200 * MHZ) {
1411				ldwin_pw = 4;
1412			} else if (pfd_freq <= 250 * MHZ) {
1413				if (dev->freq >= 5000U * MHZ &&
1414				    dev->freq < 6400U * MHZ) {
1415					ldwin_pw = 3;
1416				} else {
1417					ldwin_pw = 2;
1418				}
1419			}
1420	
1421			ret = adf4382_bleed_word_compute(dev, pfd_freq);
1422			if (ret)
1423				return ret;
1424	
1425		} else {
1426			int_mode = 1;
1427			en_bleed = 0;
1428	
1429			tmp = NO_OS_DIV_ROUND_UP(pfd_freq, MICROAMPER_PER_AMPER);
1430			tmp *= adf4382_ci_ua[dev->cp_i];
1431			tmp = NO_OS_DIV_ROUND_UP(dev->bleed_word, tmp);
1432			if (tmp <= 85)
1433				ldwin_pw = 0;
1434			else
1435				ldwin_pw = 1;
1436		}
1437	
1438		if (frac2_word) {
1439			ret = adf4382_spi_update_bits(dev, 0x28, ADF4382_VAR_MOD_EN_MSK,
1440						      0xff);
1441			if (ret)
1442				return ret;
1443		} else {
1444			ret = adf4382_spi_update_bits(dev, 0x28, ADF4382_VAR_MOD_EN_MSK,
1445						      0x0);
1446			if (ret)
1447				return ret;
1448		}
1449	
1450		ret = adf4382_spi_update_bits(dev, 0x15, ADF4382_INT_MODE_MSK,
1451					      no_os_field_prep(ADF4382_INT_MODE_MSK,
1452							      int_mode));
1453		if (ret)
1454			return ret;
1455	
1456		val = dev->bleed_word & ADF4382_FINE_BLEED_LSB_MSK;
1457		ret = adf4382_spi_write(dev, 0x1D, val);
1458		if (ret)
1459			return ret;
1460		val = (dev->bleed_word >> 8) & ADF4382_BLEED_MSB_MSK;
1461		ret = adf4382_spi_update_bits(dev, 0x1E, ADF4382_BLEED_MSB_MSK,
1462					      no_os_field_prep(ADF4382_BLEED_MSB_MSK,
1463							      val));
1464		if (ret)
1465			return ret;
1466	
1467		ret = adf4382_spi_update_bits(dev, 0x1F, ADF4382_EN_BLEED_MSK,
1468					      no_os_field_prep(ADF4382_EN_BLEED_MSK,
1469							      en_bleed));
1470		if (ret)
1471			return ret;
1472	
1473		val = mod2_word & ADF4382_MOD2WORD_LSB_MSK;
1474		ret = adf4382_spi_write(dev, 0x1A, val);
1475		if (ret)
1476			return ret;
1477		val = (mod2_word >> 8) & ADF4382_MOD2WORD_MID_MSK;
1478		ret = adf4382_spi_write(dev, 0x1B, val);
1479		if (ret)
1480			return ret;
1481		val = (mod2_word >> 16) & ADF4382_MOD2WORD_MSB_MSK;
1482		ret = adf4382_spi_write(dev, 0x1C, val);
1483		if (ret)
1484			return ret;
1485	
1486		val = frac2_word  & ADF4382_FRAC2WORD_LSB_MSK;
1487		ret = adf4382_spi_write(dev, 0x17, val);
1488		if (ret)
1489			return ret;
1490		val = (frac2_word >> 8)  & ADF4382_FRAC2WORD_MID_MSK;
1491		ret = adf4382_spi_write(dev, 0x18, val);
1492		if (ret)
1493			return ret;
1494		val = (frac2_word >> 16) & ADF4382_FRAC2WORD_MSB_MSK;
1495		ret = adf4382_spi_write(dev, 0x19, val);
1496		if (ret)
1497			return ret;
1498	
1499		val = frac1_word  & ADF4382_FRAC1WORD_LSB_MSK;
1500		ret = adf4382_spi_write(dev, 0x12, val);
1501		if (ret)
1502			return ret;
1503		val = (frac1_word >> 8)  & ADF4382_FRAC1WORD_MID_MSK;
1504		ret = adf4382_spi_write(dev, 0x13, val);
1505		if (ret)
1506			return ret;
1507		val = (frac1_word >> 16) & ADF4382_FRAC1WORD_MSB_MSK;
1508		ret = adf4382_spi_write(dev, 0x14, val);
1509		if (ret)
1510			return ret;
1511	
1512		val = (frac1_word >> 24) & ADF4382_FRAC1WORD_MSB;
1513		ret = adf4382_spi_update_bits(dev, 0x15, ADF4382_FRAC1WORD_MSB, val);
1514		if (ret)
1515			return ret;
1516	
1517		dclk_div1 = 2;
1518		div1 = 8;
1519		if (pfd_freq <= ADF4382_DCLK_DIV1_0_MAX) {
1520			dclk_div1 = 0;
1521			div1 = 1;
1522		} else if (pfd_freq <= ADF4382_DCLK_DIV1_1_MAX) {
1523			dclk_div1 = 1;
1524			div1 = 2;
1525		}
1526	
1527		ret = adf4382_spi_update_bits(dev, 0x24, ADF4382_DCLK_DIV1_MSK,
1528					      no_os_field_prep(ADF4382_DCLK_DIV1_MSK,
1529							      dclk_div1));
1530		if (ret)
1531			return ret;
1532	
1533		ret = adf4382_spi_update_bits(dev, 0x31, ADF4382_DCLK_MODE_MSK, 0xff);
1534		if (ret)
1535			return ret;
1536	
1537		ret = adf4382_spi_update_bits(dev, 0x31, ADF4382_CAL_CT_SEL_MSK, 0xff);
1538		if (ret)
1539			return ret;
1540	
1541		ret = adf4382_spi_update_bits(dev, 0x31, ADF4382_EN_ADC_CLK_MSK, 0xff);
1542		if (ret)
1543			return ret;
1544	
1545		//VCO automatic level calibration time
1546		ret = adf4382_spi_write(dev, 0x3A, ADF4382_VCO_CAL_ALC);
1547		if (ret)
1548			return ret;
1549	
1550		tmp = NO_OS_DIV_ROUND_UP(no_os_div_u64(pfd_freq, div1 * 400000) - 2, 4);
1551		tmp = no_os_clamp(tmp, 0U, 255U);
1552		ret = adf4382_spi_write(dev, 0x3E, tmp);
1553		if (ret)
1554			return ret;
1555	
1556		// Set LD COUNT
1557		ret = adf4382_spi_update_bits(dev, 0x2C, ADF4382_LD_COUNT_OPWR_MSK,
1558					      dev->ld_count);
1559		if (ret)
1560			return ret;
1561	
1562		ret = adf4382_spi_update_bits(dev, 0x2C, ADF4382_LDWIN_PW_MSK,
1563					      no_os_field_prep(ADF4382_LDWIN_PW_MSK,
1564							      ldwin_pw));
1565		if (ret)
1566			return ret;
1567	
1568		ret = adf4382_spi_update_bits(dev, 0x11, ADF4382_CLKOUT_DIV_MSK,
1569					      no_os_field_prep(ADF4382_CLKOUT_DIV_MSK,
1570							      clkout_div));
1571		if (ret)
1572			return ret;
1573	
1574		val = (n_int >> 8) & ADF4382_N_INT_MSB_MSK;
1575		ret = adf4382_spi_update_bits(dev, 0x11, ADF4382_N_INT_MSB_MSK, val);
1576		if (ret)
1577			return ret;
1578	
1579		// Need to set N_INT last to trigger an auto-calibration
1580		val = n_int & ADF4382_N_INT_LSB_MSK;
1581		ret = adf4382_spi_write(dev, 0x10, val);
1582		if (ret)
1583			return ret;
1584	
1585		no_os_udelay(ADF4382_LKD_DELAY_US);
1586		ret = adf4382_spi_read(dev, 0x58, &val);
1587		if (ret)
1588			return ret;
1589	
1590		locked = no_os_field_get(val, ADF4382_LOCKED_MSK);
1591		if (!locked)
1592			return -EIO;
1593	
1594		return 0;
1595	}
