1597	/**
1598	 * @brief Set the phase adjustment in pico-seconds. The phase adjust will
1599	 * enable the Bleed current option as well as delay mode to 0.
1600	 * @param dev 		- The device structure.
1601	 * @param phase_ps 	- The phase adjustment in pico-seconds.
1602	 * @return    		- 0 in case of success, negative error code otherwise.
1603	 */
1604	int adf4382_set_phase_adjust(struct adf4382_dev *dev, uint32_t phase_ps)
1605	{
1606		uint64_t phase_reg_value;
1607		uint32_t rfout_deg_ns;
1608		uint32_t phase_deg_ns;
1609		uint64_t rfout_deg_s;
1610		uint64_t phase_bleed;
1611		uint16_t phase_deg;
1612		uint64_t phase_ci;
1613		uint64_t pfd_freq;
1614		int ret;
1615	
1616		ret = adf4382_spi_update_bits(dev, 0x1E, ADF4382_EN_PHASE_RESYNC_MSK, 0xff);
1617		if (ret)
1618			return ret;
1619	
1620		ret = adf4382_spi_update_bits(dev, 0x1F, ADF4382_EN_BLEED_MSK, 0xff);
1621		if (ret)
1622			return ret;
1623	
1624		ret = adf4382_spi_update_bits(dev, 0x32, ADF4382_DEL_MODE_MSK, 0x0);
1625		if (ret)
1626			return ret;
1627	
1628		dev->phase_adj = phase_ps;
1629	
1630		//Determine the output freq. in degrees/s
1631		rfout_deg_s = 360 * dev->freq;
1632		//Convert it to degrees/ns
1633		rfout_deg_ns = no_os_div_u64(rfout_deg_s, S_TO_NS);
1634		//Determine the phase adjustment in degrees relative the output freq.
1635		phase_deg_ns = rfout_deg_ns * phase_ps;
1636		//Convert it to degrees/ps
1637		phase_deg = no_os_div_u64(phase_deg_ns, NS_TO_PS);
1638	
1639		if (phase_deg > 360) {
1640			pr_err("Phase Adjustment cannot exceed 360deg per Clock Period\n");
1641			return EINVAL;
1642		}
1643	
1644		//Phase adjustment can only be done if bleed is active, and a bleed
1645		//constant needs to be added
1646		phase_bleed = phase_deg * ADF4382_PHASE_BLEED_CNST;
1647		//The charge pump current will also need to be taken in to account
1648		phase_ci = phase_bleed * adf4382_ci_ua[dev->cp_i];
1649		phase_ci = no_os_div_u64(phase_ci, MICROAMPER_PER_AMPER);
1650	
1651		//Computation of the register value for the phase adjust
1652		pfd_freq = adf4382_pfd_compute(dev);
1653		phase_reg_value = no_os_div_u64((phase_ci * pfd_freq), (360 * dev->freq));
1654	
1655		if (phase_reg_value > 255)
1656			phase_reg_value -= 255;
1657	
1658		ret = adf4382_spi_write(dev, 0x33, phase_reg_value);
1659		if (ret)
1660			return ret;
1661	
1662		return adf4382_spi_update_bits(dev, 0x34, ADF4382_PHASE_ADJ_MSK, 0xff);
1663	}
