1701	/**
1702	 * @brief Set the EZSYNC features' initial state. Awaits the SW_SYNC toggle.
1703	 * @param dev 		- The device structure.
1704	 * @param sync	 	- The enable or disable sync.
1705	 * @return    		- Result of the writing procedure, error code otherwise.
1706	 */
1707	int adf4382_set_ezsync_setup(struct adf4382_dev *dev, bool sync)
1708	{
1709		int ret;
1710	
1711		if (!dev)
1712			return -EINVAL;
1713	
1714		if (sync == 1) {
1715			ret = adf4382_spi_update_bits(dev, 0x2A, ADF4382_PD_SYNC_MSK, 0);
1716			if (ret)
1717				return ret;
1718	
1719			ret = adf4382_spi_update_bits(dev, 0x53,
1720						      ADF4382_SYNC_SEL_MSK, 0xff);
1721			if (ret)
1722				return ret;
1723	
1724			ret = adf4382_spi_update_bits(dev, 0x1E,
1725						      ADF4382_TIMED_SYNC_MSK, 0);
1726			if (ret)
1727				return ret;
1728	
1729			ret = adf4382_spi_update_bits(dev, 0x1E,
1730						      (ADF4382_EN_REF_RST_MSK |
1731						       ADF4382_EN_PHASE_RESYNC_MSK), 0xff);
1732			if (ret)
1733				return ret;
1734	
1735		} else {
1736			ret = adf4382_spi_update_bits(dev, 0x2A, ADF4382_PD_SYNC_MSK,
1737						      0xff);
1738			if (ret)
1739				return ret;
1740		}
1741		return 0;
1742	}
