1744	/**
1745	 * @brief Set Timed SYNC features' initial state. Uses SYNC pin.
1746	 * @param dev 		- The device structure.
1747	 * @param sync	 	- The enable or disable sync.
1748	 * @return    		- Result of the writing procedure, error code otherwise.
1749	 */
1750	int adf4382_set_timed_sync_setup(struct adf4382_dev *dev, bool sync)
1751	{
1752		uint64_t pfd_freq;
1753		uint8_t delay;
1754		uint8_t val;
1755		int ret;
1756	
1757		if (!dev)
1758			return -EINVAL;
1759	
1760		if (sync == 1) {
1761			// Timed Sync
1762			ret = adf4382_spi_update_bits(dev, 0x2A, ADF4382_PD_SYNC_MSK, 0);
1763			if (ret)
1764				return ret;
1765	
1766			ret = adf4382_spi_update_bits(dev, 0x53,
1767						      ADF4382_SYNC_SEL_MSK, 0);
1768			if (ret)
1769				return ret;
1770	
1771			ret = adf4382_spi_update_bits(dev, 0x1E, (ADF4382_EN_REF_RST_MSK
1772						      | ADF4382_TIMED_SYNC_MSK
1773						      | ADF4382_EN_PHASE_RESYNC_MSK),
1774						      0xff);
1775			if (ret)
1776				return ret;
1777	
1778			pfd_freq = adf4382_pfd_compute(dev);
1779			if (pfd_freq >= 225 * MHZ) {
1780				delay = 3;
1781			} else if (pfd_freq >= 200 * MHZ) {
1782				delay = 4;
1783			} else if (pfd_freq >= 148 * MHZ) {
1784				delay = 1;
1785			} else if (pfd_freq >= 130 * MHZ) {
1786				delay = 3;
1787			} else if (pfd_freq >= 85 * MHZ) {
1788				delay = 4;
1789			} else if (pfd_freq < 85 * MHZ) {
1790				delay = 0;
1791			}
1792			ret = adf4382_spi_update_bits(dev, 0x31, ADF4382_SYNC_DEL_MSK,
1793						      no_os_field_prep
1794						      (ADF4382_SYNC_DEL_MSK, delay));
1795			if (ret)
1796				return ret;
1797	
1798			val = no_os_field_prep(ADF4382_DRCLK_DEL_MSK, delay) |
1799			      no_os_field_prep(ADF4382_DNCLK_DEL_MSK, delay);
1800			ret = adf4382_spi_update_bits(dev, 0x34,
1801						      ADF4382_DRCLK_DEL_MSK
1802						      | ADF4382_DNCLK_DEL_MSK, val);
1803	
1804			if (ret)
1805				return ret;
1806		} else {
1807			ret = adf4382_spi_update_bits(dev, 0x2A, ADF4382_PD_SYNC_MSK,
1808						      0xff);
1809			if (ret)
1810				return ret;
1811		}
1812		return 0;
1813	}
