1875	/**
1876	 * @brief Computes and sets the VCO Calibration Timeout values.
1877	 * @param dev 	- The device structure.
1878	 * @return 	- 0 in case of success or negative error code.
1879	 */
1880	int adf4382_set_vco_cal_timeout(struct adf4382_dev *dev)
1881	{
1882		uint32_t cal_count_to, cal_vtune_to, cal_vco_to;
1883		uint32_t cal_count_to_time = 235; // Default value in 23.5us steps
1884		uint8_t dclk_div1, dclk_div, val;
1885		uint64_t pfd_freq;
1886		int ret;
1887	
1888		if (!dev)
1889			return -EINVAL;
1890	
1891		pfd_freq = adf4382_pfd_compute(dev);
1892	
1893		// Read DCLK_DIV1 once
1894		ret = adf4382_spi_read(dev, 0x24, &val);
1895		if (ret)
1896			return ret;
1897		dclk_div1 = no_os_field_get(val, ADF4382_DCLK_DIV1_MSK);
1898		dclk_div = 1 << dclk_div1;
1899	
1900		// VCO Calibration Count Timeout
1901		cal_count_to = NO_OS_DIV_ROUND_CLOSEST_ULL((cal_count_to_time * pfd_freq),
1902				(10 * MHZ * dclk_div * 16));
1903		ret = adf4382_spi_write(dev, 0x37,
1904					(cal_count_to & ADF4382_CAL_COUNT_TO_MSK));
1905		if (ret)
1906			return ret;
1907	
1908		cal_vtune_to = NO_OS_DIV_ROUND_CLOSEST_ULL
1909			       (dev->max_lpf_cap_value_uf * 80000ULL * pfd_freq,
1910				420000000000ULL * dclk_div);
1911		dev->cal_vtune_to = cal_vtune_to & ADF4382_CAL_VTUNE_TO_LSB_MSK;
1912		ret = adf4382_spi_write(dev, 0x38, dev->cal_vtune_to);
1913		if (ret)
1914			return ret;
1915		ret = adf4382_spi_update_bits(dev, 0x39, ADF4382_CAL_VTUNE_TO_MSB_MSK,
1916					      no_os_field_prep(ADF4382_CAL_VTUNE_TO_MSB_MSK,
1917							      dev->cal_vtune_to >> 8));
1918		if (ret)
1919			return ret;
1920	
1921		// VCO Calibration VCO Timeout
1922		cal_vco_to = NO_OS_DIV_ROUND_CLOSEST_ULL(pfd_freq, MHZ * dclk_div);
1923		ret = adf4382_spi_write(dev, 0x3A, cal_vco_to);
1924		if (ret)
1925			return ret;
1926		return adf4382_spi_update_bits(dev, 0x3B, ADF4382_CAL_VCO_TO_MSB_MSK,
1927					       no_os_field_prep(ADF4382_CAL_VCO_TO_MSB_MSK,
1928							       cal_vco_to >> 8));
1929	}
