1983	/**
1984	 * @brief Initializes the ADF4382.
1985	 * @param dev	     - The device structure.
1986	 * @param init_param - The structure containing the device initial parameters.
1987	 * @return 	     - 0 in case of success or negative error code.
1988	 */
1989	int adf4382_init(struct adf4382_dev **dev,
1990			 struct adf4382_init_param *init_param)
1991	{
1992		struct adf4382_dev *device;
1993		bool en = true;
1994		uint8_t i;
1995		int ret;
1996	
1997		device = (struct adf4382_dev *)no_os_calloc(1, sizeof(*device));
1998		if (!device)
1999			return -ENOMEM;
2000	
2001		ret = no_os_spi_init(&device->spi_desc, init_param->spi_init);
2002		if (ret)
2003			goto error_dev;
2004	
2005		device->spi_3wire_en = init_param->spi_3wire_en;
2006		device->cmos_3v3 = init_param->cmos_3v3;
2007		device->ref_freq_hz = init_param->ref_freq_hz;
2008		device->freq = init_param->freq;
2009		device->ref_doubler_en = init_param->ref_doubler_en;
2010		device->ref_div = init_param->ref_div;
2011		device->cp_i = init_param->cp_i;
2012		device->bleed_word = init_param->bleed_word;
2013		device->ld_count = init_param->ld_count;
2014		device->phase_adj = 0;
2015		device->max_lpf_cap_value_uf = init_param->max_lpf_cap_value_uf;
2016	
2017		switch (init_param->id) {
2018		case ID_ADF4382:
2019			device->freq_max = ADF4382_RFOUT_MAX;
2020			device->freq_min = ADF4382_RFOUT_MIN;
2021			device->vco_max = ADF4382_VCO_FREQ_MAX;
2022			device->vco_min = ADF4382_VCO_FREQ_MIN;
2023			device->clkout_div_reg_val_max = ADF4382_CLKOUT_DIV_REG_VAL_MAX;
2024			break;
2025		case ID_ADF4382A:
2026			device->freq_max = ADF4382A_RFOUT_MAX;
2027			device->freq_min = ADF4382A_RFOUT_MIN;
2028			device->vco_max = ADF4382A_VCO_FREQ_MAX;
2029			device->vco_min = ADF4382A_VCO_FREQ_MIN;
2030			device->clkout_div_reg_val_max = ADF4382A_CLKOUT_DIV_REG_VAL_MAX;
2031			break;
2032		case ID_ADF4383:
2033			device->freq_max = ADF4383_RFOUT_MAX;
2034			device->freq_min = ADF4383_RFOUT_MIN;
2035			device->vco_max = ADF4383_VCO_FREQ_MAX;
2036			device->vco_min = ADF4383_VCO_FREQ_MIN;
2037			device->clkout_div_reg_val_max = ADF4382_CLKOUT_DIV_REG_VAL_MAX;
2038			break;
2039		default:
2040			goto error_spi;
2041		}
2042	
2043		ret = adf4382_spi_write(device, 0x00, ADF4382_RESET_CMD);
2044		if (ret)
2045			goto error_spi;
2046	
2047		no_os_udelay(ADF4382_POR_DELAY_US);
2048	
2049		if (device->spi_3wire_en)
2050			en = false;
2051	
2052		/* SPI set to 4 wire */
2053		ret = adf4382_spi_write(device, 0x00, ADF4382_SPI_3W_CFG(en));
2054		if (ret)
2055			goto error_spi;
2056	
2057		ret = adf4382_spi_write(device, 0x3D,
2058					no_os_field_prep(ADF4382_CMOS_OV_MSK,
2059							device->cmos_3v3));
2060		if (ret)
2061			goto error_spi;
2062	
2063		ret = adf4382_check_scratchpad(device);
2064		if (ret)
2065			goto error_spi;
2066	
2067		for (i = 0; i < NO_OS_ARRAY_SIZE(adf4382_reg_defaults); i++) {
2068			ret = adf4382_spi_write(device,
2069						adf4382_reg_defaults[i].reg,
2070						adf4382_reg_defaults[i].val);
2071			if (ret)
2072				goto error_spi;
2073		}
2074	
2075		if (ID_ADF4383 == init_param->id) {
2076			ret = adf4383_update_core_bias_table(device);
2077			if (ret)
2078				goto error_spi;
2079		}
2080	
2081		ret = adf4382_set_freq(device);
2082		if (ret)
2083			goto error_spi;
2084	
2085		ret = adf4382_set_vco_cal_timeout(device);
2086		if (ret)
2087			goto error_spi;
2088	
2089		ret = adf4382_set_out_power(device, 0, 9);
2090		if (ret)
2091			goto error_spi;
2092		ret = adf4382_set_out_power(device, 1, 9);
2093		if (ret)
2094			goto error_spi;
2095		*dev = device;
2096	
2097		return ret;
2098	error_spi:
2099		no_os_spi_remove(device->spi_desc);
2100	error_dev:
2101		no_os_free(device);
2102		return ret;
2103	}
2104	
2105	/**
2106	 * @brief Free resources allocated for ADF4382
2107	 * @param dev 	- The device structure.
2108	 * @return 	- 0 in case of success or negative error code.
2109	 */
2110	int adf4382_remove(struct adf4382_dev *dev)
2111	{
2112		int ret;
2113	
2114		ret = no_os_spi_remove(dev->spi_desc);
2115		if (ret)
2116			no_os_free(dev);
2117	
2118		return 0;
2119	}
2120	
