306	int ADF4382A_TriggerTimedSync(ADF4382A_Manager *manager)
307	{
308	    int ret;
309	
310	    if (!manager || !manager->initialized || manager->sync_method != SYNC_METHOD_TIMED) {
311	        DIAG_ERR("LO", "TriggerTimedSync REJECTED: init=%s method=%d",
312	                 (manager && manager->initialized) ? "true" : "false",
313	                 manager ? manager->sync_method : -1);
314	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
315	    }
316	
317	    DIAG("LO", "Triggering timed sync via sw_sync pulse (SYNCP/SYNCN must be present)...");
318	
319	    // Arm the sync capture on both devices via sw_sync.
320	    // With timed_sync_setup already programmed, the device will synchronize
321	    // its output dividers to the next SYNCP/SYNCN rising edge after sw_sync
322	    // is asserted.
323	    ret = adf4382_set_sw_sync(manager->tx_dev, true);
324	    if (ret) {
325	        DIAG_ERR("LO", "TX timed sw_sync SET failed: %d", ret);
326	        printf("TX timed sync trigger failed: %d\n", ret);
327	        return ADF4382A_MANAGER_ERROR_SPI;
328	    }
329	
330	    ret = adf4382_set_sw_sync(manager->rx_dev, true);
