332	        DIAG_ERR("LO", "RX timed sw_sync SET failed: %d", ret);
333	        printf("RX timed sync trigger failed: %d\n", ret);
334	        return ADF4382A_MANAGER_ERROR_SPI;
335	    }
336	
337	    // Wait for at least one sync clock cycle (60 MHz = 16.7 ns period).
338	    // 10 us is conservative — guarantees multiple sync edges are captured.
339	    no_os_udelay(10);
340	
341	    // De-assert sw_sync
342	    ret = adf4382_set_sw_sync(manager->tx_dev, false);
343	    if (ret) {
344	        DIAG_ERR("LO", "TX timed sw_sync CLEAR failed: %d", ret);
345	        printf("TX timed sync clear failed: %d\n", ret);
346	        return ADF4382A_MANAGER_ERROR_SPI;
347	    }
348	
349	    ret = adf4382_set_sw_sync(manager->rx_dev, false);
350	    if (ret) {
351	        DIAG_ERR("LO", "RX timed sw_sync CLEAR failed: %d", ret);
352	        printf("RX timed sync clear failed: %d\n", ret);
353	        return ADF4382A_MANAGER_ERROR_SPI;
354	    }
355	
356	    printf("Timed sync triggered via sw_sync pulse\n");
357	    DIAG("LO", "Timed sync trigger complete (sw_sync set + 10us + clear)");
358	    return ADF4382A_MANAGER_OK;
359	}
