361	int ADF4382A_TriggerEZSync(ADF4382A_Manager *manager)
362	{
363	    int ret;
364	    
365	    if (!manager || !manager->initialized || manager->sync_method != SYNC_METHOD_EZSYNC) {
366	        DIAG_ERR("LO", "TriggerEZSync REJECTED");
367	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
368	    }
369	
370	    DIAG("LO", "Triggering EZSync via SPI...");
371	
372	    // Trigger software sync on both devices
373	    ret = adf4382_set_sw_sync(manager->tx_dev, true);
374	    if (ret) {
375	        DIAG_ERR("LO", "TX sw_sync SET failed: %d", ret);
376	        printf("TX software sync failed: %d\n", ret);
377	        return ADF4382A_MANAGER_ERROR_SPI;
378	    }
379	
380	    ret = adf4382_set_sw_sync(manager->rx_dev, true);
381	    if (ret) {
382	        DIAG_ERR("LO", "RX sw_sync SET failed: %d", ret);
383	        printf("RX software sync failed: %d\n", ret);
384	        return ADF4382A_MANAGER_ERROR_SPI;
385	    }
386	    
387	    // Small delay for sync to take effect
388	    no_os_udelay(10);
389	
390	    // Clear software sync
391	    ret = adf4382_set_sw_sync(manager->tx_dev, false);
392	    if (ret) {
393	        DIAG_ERR("LO", "TX sw_sync CLEAR failed: %d", ret);
394	        printf("TX sync clear failed: %d\n", ret);
395	        return ADF4382A_MANAGER_ERROR_SPI;
396	    }
397	    
398	    ret = adf4382_set_sw_sync(manager->rx_dev, false);
399	    if (ret) {
400	        DIAG_ERR("LO", "RX sw_sync CLEAR failed: %d", ret);
401	        printf("RX sync clear failed: %d\n", ret);
402	        return ADF4382A_MANAGER_ERROR_SPI;
403	    }
404	
405	    printf("EZSync triggered via SPI\n");
406	    DIAG("LO", "EZSync trigger complete (set + 10us + clear)");
407	    return ADF4382A_MANAGER_OK;
408	}
