455	int ADF4382A_CheckLockStatus(ADF4382A_Manager *manager, bool *tx_locked, bool *rx_locked)
456	{
457	    uint8_t tx_status, rx_status;
458	    int ret;
459	    
460	    if (!manager || !manager->initialized || !tx_locked || !rx_locked) {
461	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
462	    }
463	    
464	    // Read lock status from registers
465	    ret = adf4382_spi_read(manager->tx_dev, 0x58, &tx_status);
466	    if (ret) {
467	        DIAG_ERR("LO", "TX lock status SPI read FAILED: %d", ret);
468	        printf("TX lock status read failed: %d\n", ret);
469	        return ADF4382A_MANAGER_ERROR_SPI;
470	    }
471	    
472	    ret = adf4382_spi_read(manager->rx_dev, 0x58, &rx_status);
473	    if (ret) {
474	        DIAG_ERR("LO", "RX lock status SPI read FAILED: %d", ret);
475	        printf("RX lock status read failed: %d\n", ret);
476	        return ADF4382A_MANAGER_ERROR_SPI;
477	    }
478	    
479	    bool tx_reg_locked = (tx_status & ADF4382_LOCKED_MSK) != 0;
480	    bool rx_reg_locked = (rx_status & ADF4382_LOCKED_MSK) != 0;
481	
482	    // Also check GPIO lock detect pins as backup
483	    bool tx_gpio_locked = HAL_GPIO_ReadPin(TX_LKDET_GPIO_Port, TX_LKDET_Pin) == GPIO_PIN_SET;
484	    bool rx_gpio_locked = HAL_GPIO_ReadPin(RX_LKDET_GPIO_Port, RX_LKDET_Pin) == GPIO_PIN_SET;
485	    
486	    // Diagnostic: show both register and GPIO readings independently
487	    DIAG("LO", "Lock check: TX reg[0x58]=0x%02X(%s) GPIO=%s | RX reg[0x58]=0x%02X(%s) GPIO=%s",
488	         tx_status, tx_reg_locked ? "LK" : "UNL", tx_gpio_locked ? "HI" : "LO",
489	         rx_status, rx_reg_locked ? "LK" : "UNL", rx_gpio_locked ? "HI" : "LO");
490	
491	    // Flag disagreement between register and GPIO
492	    if (tx_reg_locked != tx_gpio_locked) {
493	        DIAG_WARN("LO", "TX LOCK DISAGREE: reg=%s GPIO=%s -- possible pin mapping issue",
494	                  tx_reg_locked ? "LOCKED" : "UNLOCKED",
495	                  tx_gpio_locked ? "HIGH" : "LOW");
496	    }
497	    if (rx_reg_locked != rx_gpio_locked) {
498	        DIAG_WARN("LO", "RX LOCK DISAGREE: reg=%s GPIO=%s -- possible pin mapping issue",
499	                  rx_reg_locked ? "LOCKED" : "UNLOCKED",
500	                  rx_gpio_locked ? "HIGH" : "LOW");
501	    }
502	
503	    // Use both register and GPIO status
504	    *tx_locked = tx_reg_locked && tx_gpio_locked;
505	    *rx_locked = rx_reg_locked && rx_gpio_locked;
506	    
507	    return ADF4382A_MANAGER_OK;
508	}
