569	int ADF4382A_SetPhaseShift(ADF4382A_Manager *manager, uint16_t tx_phase_ps, uint16_t rx_phase_ps)
570	{
571	    if (!manager || !manager->initialized) {
572	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
573	    }
574	
575	    // Clamp phase shift values
576	    tx_phase_ps = (tx_phase_ps > PHASE_SHIFT_MAX_PS) ? PHASE_SHIFT_MAX_PS : tx_phase_ps;
577	    rx_phase_ps = (rx_phase_ps > PHASE_SHIFT_MAX_PS) ? PHASE_SHIFT_MAX_PS : rx_phase_ps;
578	
579	    DIAG("LO", "SetPhaseShift: TX=%d ps, RX=%d ps", tx_phase_ps, rx_phase_ps);
580	
581	    // Convert phase shift to duty cycle and apply
582	    if (tx_phase_ps != manager->tx_phase_shift_ps) {
583	        uint16_t duty_cycle = phase_ps_to_duty_cycle(tx_phase_ps);
584	        DIAG("LO", "TX phase: %d ps -> duty_cycle=%d/%d (TIM3 CH2 PWM)",
585	                  tx_phase_ps, duty_cycle, DELADJ_MAX_DUTY_CYCLE);
586	        ADF4382A_SetFinePhaseShift(manager, 0, duty_cycle); // 0 = TX device
587	        manager->tx_phase_shift_ps = tx_phase_ps;
588	    }
589	
590	    if (rx_phase_ps != manager->rx_phase_shift_ps) {
591	        uint16_t duty_cycle = phase_ps_to_duty_cycle(rx_phase_ps);
592	        DIAG("LO", "RX phase: %d ps -> duty_cycle=%d/%d (TIM3 CH3 PWM)",
593	                  rx_phase_ps, duty_cycle, DELADJ_MAX_DUTY_CYCLE);
594	        ADF4382A_SetFinePhaseShift(manager, 1, duty_cycle); // 1 = RX device
595	        manager->rx_phase_shift_ps = rx_phase_ps;
596	    }
597	
598	    printf("Phase shift set: TX=%d ps, RX=%d ps\n", tx_phase_ps, rx_phase_ps);
599	    return ADF4382A_MANAGER_OK;
600	}
