614	int ADF4382A_SetFinePhaseShift(ADF4382A_Manager *manager, uint8_t device, uint16_t duty_cycle)
615	{
616	    if (!manager || !manager->initialized) {
617	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
618	    }
619	
620	    // Clamp duty cycle
621	    duty_cycle = (duty_cycle > DELADJ_MAX_DUTY_CYCLE) ? DELADJ_MAX_DUTY_CYCLE : duty_cycle;
622	
623	    if (duty_cycle == 0) {
624	        // Fully OFF: stop PWM, drive pin LOW
625	        stop_deladj_pwm(device);
626	        set_deladj_pin(device, false);
627	        DIAG("LO", "Dev%d DELADJ=LOW (duty=0, PWM stopped)", device);
628	    } else if (duty_cycle >= DELADJ_MAX_DUTY_CYCLE) {
629	        // Fully ON: stop PWM, drive pin HIGH
630	        stop_deladj_pwm(device);
631	        set_deladj_pin(device, true);
632	        DIAG("LO", "Dev%d DELADJ=HIGH (duty=max, PWM stopped)", device);
633	    } else {
634	        // Intermediate: use TIM3 PWM output
635	        // The PWM output is low-pass filtered externally to produce a DC
636	        // voltage proportional to the duty cycle for the ADF4382 DELADJ input.
637	        start_deladj_pwm(device, duty_cycle);
638	        DIAG("LO", "Dev%d DELADJ PWM started: duty=%d/%d (%.1f%%)",
639	             device, duty_cycle, DELADJ_MAX_DUTY_CYCLE,
640	             (float)duty_cycle * 100.0f / DELADJ_MAX_DUTY_CYCLE);
641	    }
642	
643	    printf("Device %d DELADJ duty cycle set to %d/%d\n",
644	           device, duty_cycle, DELADJ_MAX_DUTY_CYCLE);
645	
646	    return ADF4382A_MANAGER_OK;
647	}
