649	int ADF4382A_StrobePhaseShift(ADF4382A_Manager *manager, uint8_t device)
650	{
651	    if (!manager || !manager->initialized) {
652	        return ADF4382A_MANAGER_ERROR_NOT_INIT;
653	    }
654	
655	    DIAG("LO", "Dev%d DELSTR strobe (%d us pulse)", device, DELADJ_PULSE_WIDTH_US);
656	
657	    // Generate a pulse on DELSTR pin to latch the current DELADJ value
658	    set_delstr_pin(device, true);
659	    no_os_udelay(DELADJ_PULSE_WIDTH_US);
660	    set_delstr_pin(device, false);
661	
662	    printf("Device %d phase shift strobed\n", device);
663	
664	    return ADF4382A_MANAGER_OK;
665	}
