669	static void set_chip_enable(uint16_t ce_pin, bool state)
670	{
671	    GPIO_TypeDef* port = (ce_pin == TX_CE_Pin) ? TX_CE_GPIO_Port : RX_CE_GPIO_Port;
672	    HAL_GPIO_WritePin(port, ce_pin, state ? GPIO_PIN_SET : GPIO_PIN_RESET);
673	}
674	
675	static void set_deladj_pin(uint8_t device, bool state)
676	{
677	    if (device == 0) { // TX device
678	        HAL_GPIO_WritePin(TX_DELADJ_GPIO_Port, TX_DELADJ_Pin, state ? GPIO_PIN_SET : GPIO_PIN_RESET);
679	    } else { // RX device
680	        HAL_GPIO_WritePin(RX_DELADJ_GPIO_Port, RX_DELADJ_Pin, state ? GPIO_PIN_SET : GPIO_PIN_RESET);
681	    }
682	}
683	
684	static void set_delstr_pin(uint8_t device, bool state)
685	{
686	    if (device == 0) { // TX device
687	        HAL_GPIO_WritePin(TX_DELSTR_GPIO_Port, TX_DELSTR_Pin, state ? GPIO_PIN_SET : GPIO_PIN_RESET);
688	    } else { // RX device
689	        HAL_GPIO_WritePin(RX_DELSTR_GPIO_Port, RX_DELSTR_Pin, state ? GPIO_PIN_SET : GPIO_PIN_RESET);
690	    }
691	}
692	
693	static void start_deladj_pwm(uint8_t device, uint16_t duty_cycle)
694	{
695	    // TX DELADJ → TIM3_CH2, RX DELADJ → TIM3_CH3
696	    // Timer period (ARR) is configured to DELADJ_MAX_DUTY_CYCLE in CubeMX.
697	    uint32_t channel = (device == 0) ? TIM_CHANNEL_2 : TIM_CHANNEL_3;
698	    __HAL_TIM_SET_COMPARE(&htim3, channel, (uint32_t)duty_cycle);
699	    HAL_TIM_PWM_Start(&htim3, channel);
700	}
701	
702	static void stop_deladj_pwm(uint8_t device)
703	{
704	    uint32_t channel = (device == 0) ? TIM_CHANNEL_2 : TIM_CHANNEL_3;
705	    HAL_TIM_PWM_Stop(&htim3, channel);
706	}
707	
708	static uint16_t phase_ps_to_duty_cycle(uint16_t phase_ps)
709	{
710	    // Convert phase shift in picoseconds to DELADJ duty cycle
711	    // This is a linear mapping - adjust based on your specific requirements
712	    uint32_t duty = (uint32_t)phase_ps * DELADJ_MAX_DUTY_CYCLE / PHASE_SHIFT_MAX_PS;
713	    return (uint16_t)duty;
714	}
