1068	// Configure and program AD9523 via no-os driver
1069	static int configure_ad9523(void)
1070	{
1071	    int32_t ret;
1072	    struct ad9523_dev *dev = NULL;
1073	
1074	    static struct ad9523_platform_data pdata;
1075	    memset(&pdata, 0, sizeof(pdata));
1076	
1077	    // VCXO + refs
1078	    pdata.vcxo_freq = 100000000; // 100 MHz VCXO on OSC_IN
1079	    pdata.refa_diff_rcv_en = 0;  // REFA 10 MHz single-ended
1080	    pdata.refb_diff_rcv_en = 0;  // REFB 100 MHz single-ended
1081	    pdata.osc_in_diff_en = 0;
1082	
1083	    // PLL1: keep bypass disabled so VCXO can be used as reference cleanup if desired
1084	    pdata.pll1_bypass_en = 0;
1085	    pdata.refa_r_div = 1;
1086	    pdata.refb_r_div = 1;
1087	
1088	    // PLL2: 100 MHz PFD (R2=1), N = 36 to get VCO = 3.6 GHz
1089	    pdata.pll2_ndiv_a_cnt = 0;
1090	    pdata.pll2_ndiv_b_cnt = 9; // 4*9 + 0 = 36
1091	    pdata.pll2_r2_div = 0;     // R2=1
1092	    pdata.pll2_charge_pump_current_nA = 3500; // example
1093	
1094	    // Loop filters: reasonable starting values from examples
1095	    pdata.rpole2 = RPOLE2_900_OHM;
1096	    pdata.rzero = RZERO_2000_OHM;
1097	    pdata.cpole1 = CPOLE1_24_PF;
1098	    pdata.rzero_bypass_en = 0;
1099	
1100	    // Channels array (must allocate AD9523_NUM_CHAN entries)
1101	    static struct ad9523_channel_spec channels[AD9523_NUM_CHAN];
1102	    pdata.channels = channels;
1103	    pdata.num_channels = AD9523_NUM_CHAN;
1104	
1105	    // Initialize channels to disabled defaults
1106	    for (int i=0; i<AD9523_NUM_CHAN; ++i) {
1107	        channels[i].channel_num = i;
1108	        channels[i].driver_mode = TRISTATE;
1109	        channels[i].channel_divider = 0;
1110	        channels[i].divider_phase = 0;
1111	        channels[i].use_alt_clock_src = 0;
1112	        channels[i].output_dis = 1;
1113	    }
1114	
1115	    // Map your required outputs (3.6 GHz PLL2)
1116	    // OUT0 = ADF4382A_TX= 300 MHz LVDS ( /12 )
1117	    channels[0].channel_divider = 12;
1118	    channels[0].driver_mode = LVDS_7mA;
1119	    channels[0].divider_phase = 0;
1120	    channels[0].output_dis = 0;
1121	
1122	    // OUT1 = ADF4382A_RX = 300 MHz LVDS (phase aligned with OUT0)
1123	    channels[1].channel_divider = 12;
1124	    channels[1].driver_mode = LVDS_7mA;
1125	    channels[1].divider_phase = 0;
1126	    channels[1].output_dis = 0;
1127	
1128	    // OUT4 = ADC = 400 MHz LVDS ( /9 )
1129	    channels[4].channel_divider = 9;
1130	    channels[4].driver_mode = LVDS_7mA;
1131	    channels[4].divider_phase = 0;
1132	    channels[4].output_dis = 0;
1133	
1134	    // OUT5 = FPGA_ADC = 400 MHz LVDS (phase aligned with OUT4)
1135	    channels[5].channel_divider = 9;
1136	    channels[5].driver_mode = LVDS_7mA;
1137	    channels[5].divider_phase = 0;
1138	    channels[5].output_dis = 0;
1139	
1140	    // OUT6 = FPGA_SYSTEM_CLOCK = 100 MHz LVCMOS ( /36 )
1141	    channels[6].channel_divider = 36;
1142	    channels[6].driver_mode = CMOS_CONF1;
1143	    channels[6].divider_phase = 0;
1144	    channels[6].output_dis = 0;
1145	
1146	    // OUT7 = FPGA_TEST_CLOCK = 20 MHz LVCMOS ( /180 )
1147	    channels[7].channel_divider = 180;
1148	    channels[7].driver_mode = CMOS_CONF1;
1149	    channels[7].divider_phase = 0;
1150	    channels[7].output_dis = 0;
1151	
1152	    // OUT8 = SYNC_TX = 60 MHz LVDS ( /60 )
1153	    channels[8].channel_divider = 60;
1154	    channels[8].driver_mode = LVDS_4mA;
1155	    channels[8].divider_phase = 0;
1156	    channels[8].output_dis = 0;
1157	
1158	    // OUT9 = SYNC_RX = 60 MHz LVDS (phase aligned with OUT8)
1159	    channels[9].channel_divider = 60;
1160	    channels[9].driver_mode = LVDS_4mA;
1161	    channels[9].divider_phase = 0;
1162	    channels[9].output_dis = 0;
1163	
1164	    // OUT10 = DAC = 120 MHz LVCMOS ( /30 )
1165	    channels[10].channel_divider = 30;
1166	    channels[10].driver_mode = CMOS_CONF1;
1167	    channels[10].divider_phase = 0;
1168	    channels[10].output_dis = 0;
1169	
1170	    // OUT11 = FPGA_DAC = 120 MHz LVCMOS (phase aligned with OUT10)
1171	    channels[11].channel_divider = 30;
1172	    channels[11].driver_mode = CMOS_CONF1;
1173	    channels[11].divider_phase = 0;
1174	    channels[11].output_dis = 0;
1175	
1176	    // Fill ad9523 init param
1177	    struct ad9523_init_param init_param;
1178	    memset(&init_param, 0, sizeof(init_param));
1179	
1180	    // SPI init (no_os type)
1181	    init_param.spi_init.max_speed_hz = 10000000; // 10 MHz SPI
1182	    init_param.spi_init.chip_select = 0;
1183	    init_param.spi_init.mode = NO_OS_SPI_MODE_0;
1184	    init_param.spi_init.platform_ops = &stm32_spi_ops;
1185	    init_param.spi_init.extra = &hspi4; // pass HAL handle via extra
1186	
1187	
1188	    init_param.pdata = &pdata;
1189	
1190	    DIAG_SECTION("AD9523 CONFIGURE");
1191	    DIAG("CLK", "VCXO=%lu Hz, PLL2 N=%d (4*%d+%d)=%d, R2=%d",
1192	         (unsigned long)pdata.vcxo_freq,
1193	         4 * pdata.pll2_ndiv_b_cnt + pdata.pll2_ndiv_a_cnt,
1194	         pdata.pll2_ndiv_b_cnt, pdata.pll2_ndiv_a_cnt,
1195	         4 * pdata.pll2_ndiv_b_cnt + pdata.pll2_ndiv_a_cnt,
1196	         pdata.pll2_r2_div);
1197	    DIAG("CLK", "Enabled channels: 0,1(/12=300M) 4,5(/9=400M) 6(/36=100M) 7(/180=20M) 8,9(/60=60M) 10,11(/30=120M)");
1198	
1199	    // init ad9523 defaults (fills any missing pdata defaults)
1200	    DIAG("CLK", "Calling ad9523_init() -- fills pdata defaults");
